//go:embed schema/*.sql
var snapshotFS embed.FS

type sqlFile struct {
	name    string
	content string
}

func readSnapshotSQL() ([]sqlFile, error) {
	entries, err := snapshotFS.ReadDir("schema")
	if err != nil {
		return nil, xerrors.WithStackTrace(fmt.Errorf("snapshot: read dir: %v", err))
	}

	sqlFiles := make([]sqlFile, 0)
	for _, e := range entries {
		bb, err := snapshotFS.ReadFile("schema/" + e.Name())
		if err != nil {
			return nil, xerrors.WithStackTrace(fmt.Errorf("snapshot: read %s: %v", e.Name(), err))
		}
		sqlFiles = append(sqlFiles, sqlFile{
			name:    e.Name(),
			content: xstring.FromBytes(bb),
		})
	}

	return sqlFiles, nil
}

func s2t(s string) time.Time {
	t, err := time.Parse("2006-01-02T15:04:05.999999Z", s)
	if err != nil {
		panic(err)
	}

	return t
}

func row(id int64, migration_id string, sql string, success uint8, error string, timestamp time.Time) types.Value {
	return types.StructValue(
		types.StructFieldValue("id", types.Int64Value(id)),
		types.StructFieldValue("migration_id", types.TextValue(migration_id)),
		types.StructFieldValue("sql", types.TextValue(sql)),
		types.StructFieldValue("success", types.BoolValue(success > 0)),
		types.StructFieldValue("error", types.TextValue(error)),
		types.StructFieldValue("timestamp", types.Datetime64Value(timestamp.Unix())),
	)
}

