func upsertMigrationLogData(ctx context.Context, db *ydb.Driver, migrationLogTableName string) error {
	err := db.Query().Exec(ctx, "UPSERT INTO `"+migrationLogTableName+"` (`id`, `migration_id`, `sql`, `success`, `error`, `timestamp`) "+
		"SELECT `id`, `migration_id`, `sql`, `success`, `error`, `timestamp` "+
		"FROM AS_TABLE($rows)",
		query.WithParameters(
			ydb.ParamsBuilder().
				Param("$rows").
				BeginList().
				AddItems(upsertMigrationLogRows...).
				EndList().
				Build(),
		),
	)
	if err != nil {
		return xerrors.WithStackTrace(err)
	}

	return nil
}

func createTableMigrationLog(ctx context.Context, db *ydb.Driver, migrationLogTableName string) error {
	if err := db.Query().Exec(ctx, "CREATE TABLE `"+migrationLogTableName+"` ("+
		"`id` Serial8 NOT NULL,"+
		"`migration_id` Text,"+
		"`sql` Text,"+
		"`success` Bool,"+
		"`error` Text,"+
		"`timestamp` Datetime64,"+
		"FAMILY `default` (COMPRESSION = 'off'),"+
		"PRIMARY KEY (`id`)"+
		")"+
		"WITH ("+
		"AUTO_PARTITIONING_BY_SIZE = ENABLED,"+
		"AUTO_PARTITIONING_PARTITION_SIZE_MB = 2048,"+
		"AUTO_PARTITIONING_BY_LOAD = ENABLED"+
		");"); err != nil {
		return xerrors.WithStackTrace(fmt.Errorf("snapshot: create table %q failed: %v", migrationLogTableName, err))
	}

	return nil
}

func Apply(ctx context.Context, db *ydb.Driver, migrationLogTableName string) error {
	sqlFiles, err := readSnapshotSQL()
	if err != nil {
		return xerrors.WithStackTrace(err)
	}

	for _, sqlFile := range sqlFiles {
		if err := db.Query().Exec(ctx, sqlFile.content); err != nil {
			return xerrors.WithStackTrace(fmt.Errorf("snapshot: apply %q failed: %v", sqlFile.name, err))
		}
	}

	if err := createTableMigrationLog(ctx, db, migrationLogTableName); err != nil {
		return xerrors.WithStackTrace(fmt.Errorf("snapshot: create table %q failed: %v", migrationLogTableName, err))
	}

	if err := upsertMigrationLogData(ctx, db, migrationLogTableName); err != nil {
		return xerrors.WithStackTrace(fmt.Errorf("snapshot: upsert data into table %q failed: %v", migrationLogTableName, err))
	}

	return nil
}
